int calculateMaxCoins(vector<int>& balloonNumbers) {
    int n = balloonNumbers.size();
    // Create new array with padding
    vector<int> nums(n + 2);
    nums[0] = 1;
    nums[n + 1] = 1;
    for(int i = 0; i < n; i++) {
        nums[i + 1] = balloonNumbers[i];
    }

    // DP table initialized to 0
    vector<vector<int>> dp(n + 2, vector<int>(n + 2, 0));

    for (int len = 1; len <= n; ++len) {
        for (int left = 1; left <= n - len + 1; ++left) {
            int right = left + len - 1;

            for (int k = left; k <= right; ++k) {
                int coins = nums[left - 1] * nums[k] * nums[right + 1];
                int remaining = dp[left][k - 1] + dp[k + 1][right];
                dp[left][right] = max(dp[left][right], coins + remaining);
            }
        }
    }

    return dp[1][n];
}

