int calculateMaxCoins(int n, int* balloonNumbers) {
    int size = n + 2;
    int* nums = (int*)malloc(size * sizeof(int));

    // Padding
    nums[0] = 1;
    nums[size - 1] = 1;
    for (int i = 0; i < n; i++) {
        nums[i + 1] = balloonNumbers[i];
    }

    // Allocate DP table dynamically to prevent stack overflow
    int** dp = (int**)malloc(size * sizeof(int*));
    for (int i = 0; i < size; i++) {
        dp[i] = (int*)calloc(size, sizeof(int));
    }

    for (int len = 1; len <= n; len++) {
        for (int left = 1; left <= n - len + 1; left++) {
            int right = left + len - 1;

            for (int k = left; k <= right; k++) {
                int coins = nums[left - 1] * nums[k] * nums[right + 1];
                int remaining = dp[left][k - 1] + dp[k + 1][right];
                int total = coins + remaining;

                if (total > dp[left][right]) {
                    dp[left][right] = total;
                }
            }
        }
    }

    int result = dp[1][n];

    // Cleanup
    for (int i = 0; i < size; i++) {
        free(dp[i]);
    }
    free(dp);
    free(nums);

    return result;
}

