public int calculateMaxCoins(int[] balloonNumbers) {
        int n = balloonNumbers.length;
        // Create a new array with padding 1 at both ends
        int[] nums = new int[n + 2];
        nums[0] = 1;
        nums[n + 1] = 1;
        for (int i = 0; i < n; i++) {
            nums[i + 1] = balloonNumbers[i];
        }

        // dp[i][j] stores the max coins for bursting balloons between i and j (exclusive)
        int[][] dp = new int[n + 2][n + 2];

        // Length of the range to consider (from 1 to n)
        for (int len = 1; len <= n; len++) {
            // Left boundary
            for (int left = 1; left <= n - len + 1; left++) {
                int right = left + len - 1;

                // Try every balloon k as the LAST balloon to be burst in this range
                for (int k = left; k <= right; k++) {
                    int coins = nums[left - 1] * nums[k] * nums[right + 1];
                    int remaining = dp[left][k - 1] + dp[k + 1][right];
                    dp[left][right] = Math.max(dp[left][right], coins + remaining);
                }
            }
        }

        return dp[1][n];
    }

