function calculateMaxCoins(balloonNumbers) {
    const n = balloonNumbers.length;
    // Add padding
    const nums = [1, ...balloonNumbers, 1];

    // Create DP table initialized with 0
    // Size is n + 2
    const dp = Array.from({ length: n + 2 }, () => Array(n + 2).fill(0));

    for (let len = 1; len <= n; len++) {
        for (let left = 1; left <= n - len + 1; left++) {
            let right = left + len - 1;

            for (let k = left; k <= right; k++) {
                // Calculation logic
                let coins = nums[left - 1] * nums[k] * nums[right + 1];
                let remaining = dp[left][k - 1] + dp[k + 1][right];
                dp[left][right] = Math.max(dp[left][right], coins + remaining);
            }
        }
    }

    return dp[1][n];
}
